# Generated by codex-sdd-workflow. Upgrade via the skill, not by manual copy from a different repo.
param(
    [string]$Root = "",

    [string]$CurrentTask = "",

    [string[]]$FilesTouched = @(),

    [string[]]$CommandsRun = @(),

    [string]$NextAction = "",

    [string]$CommitStatus = "",

    [string]$CommitMessage = "",

    [string]$UncommittedReason = "",

    [string]$Risk = ""
)

if ([string]::IsNullOrWhiteSpace($Root)) {
    $Root = (Resolve-Path (Join-Path $PSScriptRoot "..")).Path
}

$repoRoot = (Resolve-Path (Join-Path $Root "..")).Path
$timestamp = Get-Date -Format "yyyy-MM-dd HH:mm:ss zzz"
$branch = "unknown"
$gitRoot = ""
$gitScope = "."
try {
    $gitRoot = (git -C $repoRoot rev-parse --show-toplevel 2>$null).Trim()
    $gitRoot = ([System.IO.Path]::GetFullPath($gitRoot)).TrimEnd('\', '/')
    $repoRoot = ([System.IO.Path]::GetFullPath($repoRoot)).TrimEnd('\', '/')
    $Root = ([System.IO.Path]::GetFullPath($Root)).TrimEnd('\', '/')
    $branch = (git -C $gitRoot symbolic-ref --quiet --short HEAD 2>$null).Trim()
    if ([string]::IsNullOrWhiteSpace($branch)) {
        $branch = "unborn-or-detached"
    }
    if ($repoRoot -eq $gitRoot) {
        $gitScope = "."
    } elseif ($repoRoot.StartsWith("$gitRoot\", [System.StringComparison]::OrdinalIgnoreCase)) {
        $gitScope = $repoRoot.Substring($gitRoot.Length + 1)
    } else {
        $gitScope = "."
    }
} catch {
}

$gitStatus = @()
try {
    if ($gitRoot) {
        $gitStatus = @(git -C $gitRoot status --short -- $gitScope 2>$null)
    } else {
        $gitStatus = @(git -C $repoRoot status --short 2>$null)
    }
} catch {
}

Write-Output "## Session Handoff"
Write-Output ""
Write-Output "- [x] timestamp: $timestamp"
Write-Output "- [x] branch: $branch"
Write-Output "- [x] git scope: $gitScope"
Write-Output "- [ ] active task: $CurrentTask"
Write-Output "- [ ] 涉及文件:"
if ($FilesTouched.Count -gt 0) {
    foreach ($item in $FilesTouched) {
        Write-Output "  - [ ] $item"
    }
} else {
    Write-Output "  - [ ] "
}

Write-Output "- [ ] 执行命令:"
if ($CommandsRun.Count -gt 0) {
    foreach ($item in $CommandsRun) {
        Write-Output "  - [ ] $item"
    }
} else {
    Write-Output "  - [ ] "
}

Write-Output "- [ ] 未解决风险或 blocker：$Risk"
Write-Output "- [ ] commit status: $CommitStatus"
Write-Output "- [ ] 未提交原因: $UncommittedReason"
Write-Output "- [ ] 推荐 commit message: $CommitMessage"
Write-Output "- [ ] 推荐的下一步明确动作：$NextAction"
Write-Output "- [ ] backlog 条目："
Write-Output "- [ ] 等待用户决策："
Write-Output "- [ ] 无需下一步原因："
Write-Output "- [x] git 状态快照:"
if ($gitStatus.Count -gt 0) {
    foreach ($line in $gitStatus) {
        Write-Output "  - [x] $line"
    }
} else {
    Write-Output "  - [x] 工作区干净或 git 不可用"
}
